#include <iostream>
#include <fstream>
#include <pin.H>

ofstream outfile;

// 在AES_set_encrypt_key调用前记录密钥
VOID BeforeSetKey(CHAR *key, UINT32 bits) {
    outfile << "AES key (" << bits << " bits): ";
    for (int i = 0; i < bits/8; i++) {
        outfile << hex << (int)(unsigned char)key[i];
    }
    outfile << endl;
}

// 在AES_encrypt调用前记录明文和密文
VOID BeforeEncrypt(CHAR *in, CHAR *out, VOID *key) {
    outfile << "Plaintext: ";
    for (int i = 0; i < 16; i++) {
        outfile << hex << (int)(unsigned char)in[i];
    }
    outfile << endl;
}

// 在AES_encrypt调用后记录密文
VOID AfterEncrypt(CHAR *out) {
    outfile << "Ciphertext: ";
    for (int i = 0; i < 16; i++) {
        outfile << hex << (int)(unsigned char)out[i];
    }
    outfile << endl;
