// 插桩函数
VOID ImageLoad(IMG img, VOID *v) {
    RTN rtn;
    rtn = RTN_FindByName(img, "AES_set_encrypt_key");
    if (RTN_Valid(rtn)) {
        RTN_Open(rtn);
        RTN_InsertCall(rtn, IPOINT_BEFORE, (AFUNPTR)BeforeSetKey,
                       IARG_FUNCARG_ENTRYPOINT_VALUE, 0,
