import frida
import sys

def on_message(message, data):
    print(message)

# 附加到目标进程
session = frida.attach("malware.exe")
script = session.create_script("""
    // Hook IsDebuggerPresent
    var IsDebuggerPresent = Module.findExportByName("kernel32.dll", "IsDebuggerPresent");
    Interceptor.attach(IsDebuggerPresent, {
        onLeave: function(retval) {
            console.log("IsDebuggerPresent called, returning 0");
            retval.replace(0);  // 返回假
        }
    });

    // Hook NtQueryInformationProcess
    var ntdll = Module.findExportByName("ntdll.dll", "NtQueryInformationProcess");
    Interceptor.attach(ntdll, {
        onEnter: function(args) {
            var ProcessInformationClass = args[1].toInt32();
            if (ProcessInformationClass === 7) { // ProcessDebugPort
                console.log("NtQueryInformationProcess with ProcessDebugPort, patching");
                // 修改返回值为0
                this.patch = true;
            }
        },
        onLeave: function(retval) {
            if (this.patch) {
                // 将输出缓冲区置零
                var buffer = this.context.rdx; // 根据架构调整
                buffer.writeByteArray([0,0,0,0]);
            }
        }
    });

    // 绕过TLS回调：在模块加载时设置断点
    // 此处省略复杂实现，通常通过修改PEB的TLS表或提前Hook
""")
script.on('message', on_message)
script.load()
sys.stdin.read()
